sql:
SELECT AVG(score) as average_score, AVG(volume) as average_volume
FROM keywords
WHERE score > 50;

SELECT ko.opportunity_type 
FROM keyword_opportunities ko 
WHERE ko.opportunity_score > (
    SELECT AVG(opportunity_score) 
    FROM keyword_opportunities
);

SELECT COUNT(*) AS total_number_of_broad_keywords
FROM keywords
WHERE keyword_type = 'broad';

SELECT keyword_category, AVG(cpc) AS average_cpc
FROM keywords
GROUP BY keyword_category;

SELECT keyword 
FROM keywords 
WHERE keyword_type = 'Long-tail';

SELECT opportunity_type, opportunity_score
FROM keyword_opportunities
WHERE keyword_id = 50;

SELECT keyword
FROM keywords
WHERE volume > (SELECT AVG(volume) FROM keywords);

SELECT keyword_category, AVG(cpc) AS average_cpc
FROM keywords
GROUP BY keyword_category;
